def analisar_texto(texto):
    linhas = len(texto.split('\n'))
    palavras = len(texto.split())
    caracteres = len(texto.replace(' ', '').replace('\n', ''))
    return {'linhas': linhas, 'palavras': palavras, 'caracteres': caracteres}
